class EventEmitter {
  constructor() {
    this.events = new Map();
  }

  on(event, listener) {
    if (!this.events.has(event)) {
      this.events.set(event, []);
    }
    this.events.get(event).push({ listener, once: false });
    return this;
  }

  once(event, listener) {
    if (!this.events.has(event)) {
      this.events.set(event, []);
    }
    this.events.get(event).push({ listener, once: true });
    return this;
  }

  emit(event, ...args) {
    if (!this.events.has(event)) return false;
    const listeners = this.events.get(event);
    const remaining = [];
    for (const entry of listeners) {
      entry.listener.apply(this, args);
      if (!entry.once) remaining.push(entry);
    }
    this.events.set(event, remaining);
    return true;
  }

  off(event, listener) {
    if (!this.events.has(event)) return this;
    const filtered = this.events.get(event)
      .filter(entry => entry.listener !== listener);
    this.events.set(event, filtered);
    return this;
  }

  listenerCount(event) {
    return this.events.has(event) ? this.events.get(event).length : 0;
  }
}
