class Response {
  constructor() {
    this.statusCode = 200;
    this.body = '';
  }

  set(key, value) {
    if (typeof key === 'string') {
      this[key] = value;
    } else {
      for (const [k, v] of Object.entries(value)) {
        this[k] = v;
      }
    }
  }
