class StateMachine {
  constructor(config) {
    this.states = config.states;
    this.currentState = config.initial;
    this.context = config.context || {};
    this.listeners = new Map();
  }

  transition(event) {
    const stateConfig = this.states[this.currentState];
    if (!stateConfig || !stateConfig.on || !stateConfig.on[event]) {
      console.warn(`No transition for event '${event}' in state '${this.currentState}'`);
      return this;
    }

    const transition = stateConfig.on[event];
    const target = typeof transition === 'string' ? transition : transition.target;
    const action = typeof transition === 'object' ? transition.action : null;
    const guard = typeof transition === 'object' ? transition.guard : null;

    if (guard && !guard(this.context)) {
      return this;
    }

    const prevState = this.currentState;

    // Exit actions
    if (stateConfig.onExit) stateConfig.onExit(this.context);

    // Transition action
    if (action) action(this.context);

    this.currentState = target;

    // Entry actions
    const newStateConfig = this.states[this.currentState];
    if (newStateConfig && newStateConfig.onEntry) newStateConfig.onEntry(this.context);

    this._emit('transition', { from: prevState, to: this.currentState, event });
    return this;
  }

  on(eventName, callback) {
    if (!this.listeners.has(eventName)) this.listeners.set(eventName, []);
    this.listeners.get(eventName).push(callback);
    return this;
  }

  _emit(eventName, data) {
    (this.listeners.get(eventName) || []).forEach(cb => cb(data));
  }

  get state() { return this.currentState; }
  matches(state) { return this.currentState === state; }
}
